sql:
SELECT teams.team_name
FROM teams
INNER JOIN leagues ON teams.team_id = leagues.champion_team_id;

external_knowledge:
- "stands as the beacon of triumph" metaphorically refers to the team with the highest points; 
- "shining its light the brightest" metaphorically indicates the team that leads in competition; 
- "vast ocean" metaphorically describes the league as a large and competitive environment; 
- "amassing the greatest treasure of points" metaphorically refers to accumulating the highest number of points.

sql:
SELECT t.team_name, t.coach_name
FROM teams t
JOIN rankings r ON t.team_id = r.team_id
WHERE r.pts_avg = (
  SELECT MAX(pts_avg) FROM rankings
);

SELECT e.*
FROM events e
WHERE e.league_id = (
  SELECT league_id FROM leagues WHERE league_name = 'National Football League'
) 
AND e.champion_team_id IN (
  SELECT team_id FROM team_leagues WHERE league_id = (
    SELECT league_id FROM leagues WHERE league_name = 'International Hockey League'
  )
);

SELECT AVG(m.attendance) AS average_attendance
FROM matches m
WHERE m.team_id IN (
    SELECT l.champion_team_id
    FROM leagues l
);

SELECT teams.team_name, rankings.total_pts 
FROM teams 
INNER JOIN rankings ON teams.team_id = rankings.team_id;
